// VULNERABLE: State change logger for Redux/Context
class StateLogger {
  static logStateChange(storeName, previousState, newState, action = null) {
    console.log('═══════════════════════════════════════');
    console.log('[STATE CHANGE]');
    console.log('Store:', storeName);
    console.log('Previous State:', JSON.stringify(previousState, null, 2));
    console.log('New State:', JSON.stringify(newState, null, 2));
    if (action) {
      console.log('Action:', JSON.stringify(action, null, 2));
    }
    console.log('Timestamp:', new Date().toISOString());
    console.log('═══════════════════════════════════════');
  }

  static createReduxLogger() {
    return store => next => action => {
      const previousState = store.getState();
      console.log('═══════════════════════════════════════');
      console.log('[REDUX ACTION]');
      console.log('Action:', JSON.stringify(action, null, 2));
      console.log('Previous State:', JSON.stringify(previousState, null, 2));
      console.log('Timestamp:', new Date().toISOString());
      
      const result = next(action);
      
      const newState = store.getState();
      console.log('New State:', JSON.stringify(newState, null, 2));
      console.log('═══════════════════════════════════════');
      
      return result;
    };
  }
}

